import os
from flask import Flask, send_file, abort
from werkzeug.utils import safe_join

app = Flask(__name__)

UPLOAD_DIRECTORY = os.path.abspath('uploads')

# Ensure the uploads directory exists
os.makedirs(UPLOAD_DIRECTORY, exist_ok=True)

@app.route('/uploads/<path:filename>')
def serve_legacy_file(filename):
    """
    Serve static files from the uploads directory with backward compatibility
    for legacy file naming conventions.
    """
    # Use safe_join to prevent path traversal attacks
    file_path = safe_join(UPLOAD_DIRECTORY, filename)
    
    # safe_join returns None if the path would escape the base directory
    if file_path is None:
        abort(404)
    
    # Resolve to canonical absolute path
    try:
        canonical_path = os.path.realpath(file_path)
    except (OSError, ValueError):
        abort(404)
    
    # Ensure the canonical path is within the upload directory
    if not canonical_path.startswith(os.path.realpath(UPLOAD_DIRECTORY) + os.sep):
        abort(404)
    
    # Check if file exists and is a file (not a directory)
    if not os.path.isfile(canonical_path):
        abort(404)
    
    try:
        return send_file(canonical_path)
    except Exception:
        abort(404)

